// JavaScript — no rules
function greet(user) {
  user.name = 'hacked'; // mutates!
}

// Rust — borrowing with rules
fn greet(user: &User) {
  // Can read user.name
  // CANNOT mutate (it's &, not &mut)
}

fn update(user: &mut User) {
  user.name = String::from("new");
  // Only ONE &mut at a time
}

// JavaScript — GC saves you
function getRef() {
  let data = [1, 2, 3];
  return data; // GC keeps it alive
}

// Rust — compiler proves validity
fn get_ref() -> &Vec<i32> {
  let data = vec![1, 2, 3];
  return &data;
  // COMPILE ERROR: data dropped here
  // reference would be dangling
}
